sql:
SELECT * 
FROM voting_results 
WHERE player_id = '0';

external_knowledge:
- 'typical voting results' refers to the average number of votes;
- 'type of group' refers to the category of players;
- 'people participate in' refers to the players in each category.

sql:
SELECT player_id, SUM(votes) AS total_votes
FROM voting_results
GROUP BY player_id;

SELECT username, role, strftime('%Y', 'now') - strftime('%Y', created_at) AS age
FROM users
WHERE role = 'researcher' AND strftime('%Y', 'now') - strftime('%Y', created_at) BETWEEN 30 AND 40;

external_knowledge:
'Notable figures' refers to players who were inducted;
'Got the nod' means they were inducted (inducted = 'Y');
'Year they first became eligible' means the year of eligibility was 1982;
'Early 80s' refers to the year 1982;
'What their final tally was like' refers to the vote they received.

sql:
SELECT v.name
FROM voters v
INNER JOIN users u ON v.voter_id = u.user_id;

SELECT COUNT(*) FROM votes v
JOIN voters vo ON v.voter_id = vo.voter_id
WHERE vo.name = 'John Smith';

SELECT p.name, v.percentage_votes AS Highest_Vote_Percentage
FROM players p
JOIN voting_results v ON p.player_id = v.player_id
WHERE v.percentage_votes = (
    SELECT MAX(percentage_votes) FROM voting_results
);
